/** Get admin1 list for a country */
export function getAdmin1(countryCode: string): Admin1Entry[] {
  return ADMIN_DIVISIONS[countryCode]?.admin1 ?? [];
}

/** Get admin2 list for a country, optionally filtered by parent admin1 GID */
export function getAdmin2(countryCode: string, parentGid?: string): Admin2Entry[] {
  const all = ADMIN_DIVISIONS[countryCode]?.admin2 ?? [];
  if (!parentGid) return all;
  return all.filter((a) => a.parentGid === parentGid);
}

/** Get admin level type labels for a country */
export function getAdminLevelTypes(countryCode: string): Record<string, AdminLevelDef> {
  return ADMIN_DIVISIONS[countryCode]?.levelTypes ?? {};
}

